use std::collections::HashSet;

fn max_non_adjacent_sum(nums: &[u32]) -> u32 {
    if nums.is_empty() {
        return 0;
    }

    let mut include = 0u32;
    let mut exclude = 0u32;
    let mut computed_sums: HashSet<u32> = HashSet::with_capacity(1500);

    for &num in nums {
        let new_exclude = include.max(exclude);

        include = exclude + num;
        exclude = new_exclude;

        if computed_sums.len() < 1500 {
            computed_sums.insert(include);
            computed_sums.insert(exclude);
        }
    }

    include.max(exclude)
}

fn main() {
    let nums = vec![3, 2, 5, 10, 7];
    let result = max_non_adjacent_sum(&nums);
