class Bookstore {
private:
    std::map<int, Product> catalog; // Key: product ID, Value: Product details (structured map)
    double total = 0.0;

public:
    void addProduct(int id, const Product& product) {
        if (catalog.size() < 500) {
            catalog[id] = product;
        } else {
            std::cout << "Catalog is full. Cannot add more products.\n";
        }
    }

    void removeProduct(int id) {
        catalog.erase(id);
    }

    void calculateTotal() {
        total = 0.0;
        for (const auto& entry : catalog) {
            const Product& product = entry.second;
            double discountedPrice = product.price * (1 - product.discount / 100.0);
            total += discountedPrice;
        }
    }

    void displayTotal() const {
        std::cout << "Total Price: $" << std::fixed << std::setprecision(2) << total << "\n";
    }

    void displayCatalog() const {
        for (const auto& entry : catalog) {
            const Product& product = entry.second;
            std::cout << "ID: " << entry.first
                      << ", Name: " << product.name
                      << ", Genre: " << product.genre
                      << ", Price: $" << std::fixed << std::setprecision(2) << product.price
                      << ", Discount: " << product.discount << "%\n";
        }
    }

    void sortCatalogByPrice() {
        std::vector<std::pair<int, Product>> sortedCatalog(catalog.begin(), catalog.end());
        std::sort(sortedCatalog.begin(), sortedCatalog.end(),
                  [](const std::pair<int, Product>& a, const std::pair<int, Product>& b) {
                      return a.second.price < b.second.price;
                  });

        catalog.clear();
        for (const auto& entry : sortedCatalog) {
            catalog[entry.first] = entry.second;
        }
