class TaskManager:
    def __init__(self):
        self.pq, self.task_map = [], {}

    def add_task(self, task_id, desc, ddl):
        if len(self.pq) >= 50: raise Exception("Max tasks reached.")
        t = (self._time(ddl), task_id, desc)
        heapq.heappush(self.pq, t)
        self.task_map[task_id] = t

    def update_task(self, task_id, desc=None, ddl=None):
        if task_id not in self.task_map: raise Exception("Task not found.")
        self.delete_task(task_id)
        desc = desc or self.task_map[task_id][2]
        self.add_task(task_id, desc, ddl or self._date(self.task_map[task_id][0]))

    def delete_task(self, task_id):
        if task_id in self.task_map:
            self.pq.remove(self.task_map[task_id])
            heapq.heapify(self.pq)
            del self.task_map[task_id]

    def get_tasks(self):
        return [(tid, desc, self._date(t)) for t, tid, desc in sorted(self.pq)]

    def _time(self, date_str):
        return time.mktime(time.strptime(date_str, "%Y-%m-%d"))

    def _date(self, t):
        return time.strftime("%Y-%m-%d", time.localtime(t))

