    void addItem(const std::string& name, int urgency) {
        if (inventoryQueue.size() >= MAX_ITEMS) {
            throw std::runtime_error("Inventory is full, cannot add more items.");
        }
        inventoryQueue.push({name, urgency});
    }

    void removeItem() {
        if (inventoryQueue.empty()) {
            throw std::runtime_error("Cannot remove item: Inventory is empty.");
        }
        inventoryQueue.pop();
    }

    Item retrieveTopItem() {
        if (inventoryQueue.empty()) {
            throw std::runtime_error("Cannot retrieve item: Inventory is empty.");
        }
        return inventoryQueue.top();
    }

    bool isEmpty() const {
        return inventoryQueue.empty();
    }
};

