int longestConsecutiveSequence(vector<int>& nums) {
    unordered_map<int, bool> hashMap;
    if (nums.size() > 1000) return 0;

    for (int num : nums) {
        hashMap[num] = true;
    }

    int longest = 0;
    for (int num : nums) {
        if (!hashMap[num - 1]) {
            int currentNum = num;
            int streak = 0;

            while (hashMap[currentNum]) {
                streak++;
                currentNum++;
            }
            longest = max(longest, streak);
