void uniquePermutations(std::vector<int>& nums) {
    std::set<std::vector<int>> uniquePerms;
    std::sort(nums.begin(), nums.end());
    do {
        uniquePerms.insert(nums);
        if (uniquePerms.size() > 1500) break;
    } while (std::next_permutation(nums.begin(), nums.end()));

    for (const auto& perm : uniquePerms) {
        for (int num : perm) {
            std::cout << num << " ";
        }
        std::cout << "\n";
    }
}

